"""
Launch Interceptor Program — DECIDE (Knight & Leveson, 1986).
Single-file implementation per workspace specification.
"""

from __future__ import annotations

import math
from typing import Any, List, Optional, Sequence, Tuple

PI = 3.1415926535


def realcompare(a: float, b: float) -> str:
    """Compare two reals using six significant digits; returns LT, EQ, or GT."""

    def round6(x: float) -> float:
        if x == 0.0:
            return 0.0
        sign = -1.0 if x < 0 else 1.0
        ax = abs(x)
        m = math.floor(math.log10(ax))
        scale = 10 ** (5 - m)
        return sign * round(ax * scale) / scale

    ra = round6(a)
    rb = round6(b)
    if ra < rb:
        return "LT"
    if ra > rb:
        return "GT"
    return "EQ"


def _dist(x0: float, y0: float, x1: float, y1: float) -> float:
    return math.hypot(x1 - x0, y1 - y0)


def _triangle_area(ax: float, ay: float, bx: float, by: float, cx: float, cy: float) -> float:
    return abs((bx - ax) * (cy - ay) - (by - ay) * (cx - ax)) / 2.0


def _smallest_enclosing_circle_radius(
    ax: float, ay: float, bx: float, by: float, cx: float, cy: float
) -> float:
    """Minimum radius of a circle containing the three points (same plane)."""
    d_ab = _dist(ax, ay, bx, by)
    d_bc = _dist(bx, by, cx, cy)
    d_ac = _dist(ax, ay, cx, cy)
    area = _triangle_area(ax, ay, bx, by, cx, cy)

    if realcompare(area, 0.0) == "EQ":
        return max(d_ab, d_bc, d_ac) / 2.0

    # Longest side c; obtuse/right iff c^2 >= a^2 + b^2 (other two sides a, b)
    lengths = sorted([d_ab, d_bc, d_ac], reverse=True)
    c_len = lengths[0]
    s2 = lengths[1] * lengths[1] + lengths[2] * lengths[2]

    c2 = c_len * c_len
    cmp_obt = realcompare(c2, s2)
    if cmp_obt == "GT" or cmp_obt == "EQ":
        return c_len / 2.0

    # Acute / non-obtuse: circumradius
    return (d_ab * d_bc * d_ac) / (4.0 * area)


def _quadrant(x: float, y: float) -> int:
    """Quadrant I..IV with axis tie-breaking per spec examples."""
    rx0 = realcompare(x, 0.0)
    ry0 = realcompare(y, 0.0)
    if rx0 == "GT":
        if ry0 == "LT":
            return 4
        return 1
    if rx0 == "LT":
        if ry0 == "GT":
            return 2
        if ry0 == "LT":
            return 3
        return 2
    # x == 0
    if ry0 == "GT":
        return 1
    if ry0 == "LT":
        return 3
    return 1


def _angle_at_vertex(
    ax: float, ay: float, vx: float, vy: float, bx: float, by: float
) -> Optional[float]:
    """Angle at vertex (smaller angle between rays to A and B), or None if undefined."""
    v1x, v1y = ax - vx, ay - vy
    v2x, v2y = bx - vx, by - vy
    if realcompare(v1x, 0.0) == "EQ" and realcompare(v1y, 0.0) == "EQ":
        return None
    if realcompare(v2x, 0.0) == "EQ" and realcompare(v2y, 0.0) == "EQ":
        return None
    len1 = math.hypot(v1x, v1y)
    len2 = math.hypot(v2x, v2y)
    dot = v1x * v2x + v1y * v2y
    cosang = dot / (len1 * len2)
    if cosang > 1.0:
        cosang = 1.0
    elif cosang < -1.0:
        cosang = -1.0
    return math.acos(cosang)


def _point_line_distance(
    px: float,
    py: float,
    x0: float,
    y0: float,
    x1: float,
    y1: float,
) -> float:
    """Perpendicular distance from P to infinite line (x0,y0)-(x1,y1); degenerate: dist to (x0,y0)."""
    if realcompare(x0, x1) == "EQ" and realcompare(y0, y1) == "EQ":
        return math.hypot(px - x0, py - y0)
    num = abs((y1 - y0) * px - (x1 - x0) * py + x1 * y0 - y1 * x0)
    den = math.hypot(y1 - y0, x1 - x0)
    return num / den


def _lic_cmv(
    numpoints: int,
    x: Sequence[float],
    y: Sequence[float],
    p: dict[str, Any],
) -> List[bool]:
    length1 = float(p["LENGTH1"])
    radius1 = float(p["RADIUS1"])
    epsilon = float(p["EPSILON"])
    area1 = float(p["AREA1"])
    q_pts = int(p["Q_PTS"])
    quads = int(p["QUADS"])
    dist_p = float(p["DIST"])
    n_pts = int(p["N_PTS"])
    k_pts = int(p["K_PTS"])
    a_pts = int(p["A_PTS"])
    b_pts = int(p["B_PTS"])
    c_pts = int(p["C_PTS"])
    d_pts = int(p["D_PTS"])
    e_pts = int(p["E_PTS"])
    f_pts = int(p["F_PTS"])
    g_pts = int(p["G_PTS"])
    length2 = float(p["LENGTH2"])
    radius2 = float(p["RADIUS2"])
    area2 = float(p["AREA2"])

    cmv = [False] * 15

    # LIC 1
    for i in range(numpoints - 1):
        d = _dist(x[i], y[i], x[i + 1], y[i + 1])
        if realcompare(d, length1) == "GT":
            cmv[0] = True
            break

    # LIC 2
    for i in range(numpoints - 2):
        r = _smallest_enclosing_circle_radius(x[i], y[i], x[i + 1], y[i + 1], x[i + 2], y[i + 2])
        if realcompare(r, radius1) == "GT":
            cmv[1] = True
            break

    # LIC 3
    for i in range(numpoints - 2):
        ang = _angle_at_vertex(x[i], y[i], x[i + 1], y[i + 1], x[i + 2], y[i + 2])
        if ang is None:
            continue
        low = PI - epsilon
        high = PI + epsilon
        if realcompare(ang, low) == "LT" or realcompare(ang, high) == "GT":
            cmv[2] = True
            break

    # LIC 4
    for i in range(numpoints - 2):
        ar = _triangle_area(x[i], y[i], x[i + 1], y[i + 1], x[i + 2], y[i + 2])
        if realcompare(ar, area1) == "GT":
            cmv[3] = True
            break

    # LIC 5
    for start in range(numpoints - q_pts + 1):
        seen: set[int] = set()
        for j in range(start, start + q_pts):
            seen.add(_quadrant(x[j], y[j]))
        if len(seen) > quads:
            cmv[4] = True
            break

    # LIC 6
    for i in range(numpoints - 1):
        dx = x[i + 1] - x[i]
        if realcompare(dx, 0.0) == "LT":
            cmv[5] = True
            break

    # LIC 7
    if numpoints >= 3:
        for start in range(numpoints - n_pts + 1):
            x0, y0 = x[start], y[start]
            x1, y1 = x[start + n_pts - 1], y[start + n_pts - 1]
            if realcompare(x0, x1) == "EQ" and realcompare(y0, y1) == "EQ":
                for j in range(start + 1, start + n_pts - 1):
                    d0 = _dist(x[j], y[j], x0, y0)
                    if realcompare(d0, dist_p) == "GT":
                        cmv[6] = True
                        break
                if cmv[6]:
                    break
            else:
                for j in range(start + 1, start + n_pts - 1):
                    dpl = _point_line_distance(x[j], y[j], x0, y0, x1, y1)
                    if realcompare(dpl, dist_p) == "GT":
                        cmv[6] = True
                        break
                if cmv[6]:
                    break

    # LIC 8
    if numpoints >= 3:
        span = k_pts + 1
        for i in range(numpoints - span):
            j = i + span
            d = _dist(x[i], y[i], x[j], y[j])
            if realcompare(d, length1) == "GT":
                cmv[7] = True
                break

    # LIC 9
    if numpoints >= 5:
        span = a_pts + b_pts + 2
        for i in range(numpoints - span):
            r = _smallest_enclosing_circle_radius(
                x[i], y[i],
                x[i + a_pts + 1], y[i + a_pts + 1],
                x[i + a_pts + b_pts + 2], y[i + a_pts + b_pts + 2],
            )
            if realcompare(r, radius1) == "GT":
                cmv[8] = True
                break

    # LIC 10
    if numpoints >= 5:
        span = c_pts + d_pts + 2
        for i in range(numpoints - span):
            ang = _angle_at_vertex(
                x[i], y[i],
                x[i + c_pts + 1], y[i + c_pts + 1],
                x[i + c_pts + d_pts + 2], y[i + c_pts + d_pts + 2],
            )
            if ang is None:
                continue
            low = PI - epsilon
            high = PI + epsilon
            if realcompare(ang, low) == "LT" or realcompare(ang, high) == "GT":
                cmv[9] = True
                break

    # LIC 11
    if numpoints >= 5:
        span = e_pts + f_pts + 2
        for i in range(numpoints - span):
            ar = _triangle_area(
                x[i], y[i],
                x[i + e_pts + 1], y[i + e_pts + 1],
                x[i + e_pts + f_pts + 2], y[i + e_pts + f_pts + 2],
            )
            if realcompare(ar, area1) == "GT":
                cmv[10] = True
                break

    # LIC 12
    if numpoints >= 3:
        span = g_pts + 1
        for i in range(numpoints - span):
            j = i + span
            dx = x[j] - x[i]
            if realcompare(dx, 0.0) == "LT":
                cmv[11] = True
                break

    # LIC 13
    if numpoints >= 3:
        span = k_pts + 1
        gt_len1 = False
        lt_len2 = False
        for i in range(numpoints - span):
            j = i + span
            d = _dist(x[i], y[i], x[j], y[j])
            if realcompare(d, length1) == "GT":
                gt_len1 = True
            if realcompare(d, length2) == "LT":
                lt_len2 = True
            if gt_len1 and lt_len2:
                break
        cmv[12] = gt_len1 and lt_len2

    # LIC 14
    if numpoints >= 5:
        span = a_pts + b_pts + 2
        part1 = False
        part2 = False
        for i in range(numpoints - span):
            r = _smallest_enclosing_circle_radius(
                x[i], y[i],
                x[i + a_pts + 1], y[i + a_pts + 1],
                x[i + a_pts + b_pts + 2], y[i + a_pts + b_pts + 2],
            )
            if realcompare(r, radius1) == "GT":
                part1 = True
            if realcompare(r, radius2) == "LT" or realcompare(r, radius2) == "EQ":
                part2 = True
            if part1 and part2:
                break
        cmv[13] = part1 and part2

    # LIC 15
    if numpoints >= 5:
        span = e_pts + f_pts + 2
        part1 = False
        part2 = False
        for i in range(numpoints - span):
            ar = _triangle_area(
                x[i], y[i],
                x[i + e_pts + 1], y[i + e_pts + 1],
                x[i + e_pts + f_pts + 2], y[i + e_pts + f_pts + 2],
            )
            if realcompare(ar, area1) == "GT":
                part1 = True
            if realcompare(ar, area2) == "LT":
                part2 = True
            if part1 and part2:
                break
        cmv[14] = part1 and part2

    return cmv


def _build_pum(
    cmv: Sequence[bool],
    lcm: Sequence[Sequence[str]],
    pum_diag: Sequence[bool],
) -> List[List[bool]]:
    n = 15
    pum: List[List[bool]] = [[False] * n for _ in range(n)]
    for i in range(n):
        pum[i][i] = bool(pum_diag[i])
    for i in range(n):
        for j in range(n):
            if i == j:
                continue
            conn = lcm[i][j]
            if conn == "NOTUSED":
                pum[i][j] = True
            elif conn == "ANDD":
                pum[i][j] = cmv[i] and cmv[j]
            elif conn == "ORR":
                pum[i][j] = cmv[i] or cmv[j]
            else:
                raise ValueError("invalid LCM connector")
    return pum


def _build_fuv(pum: Sequence[Sequence[bool]]) -> List[bool]:
    n = 15
    fuv = [False] * n
    for i in range(n):
        if not pum[i][i]:
            fuv[i] = True
            continue
        all_true = True
        for j in range(n):
            if not pum[i][j]:
                all_true = False
                break
        fuv[i] = all_true
    return fuv


def decide(
    numpoints: int,
    x: Sequence[float],
    y: Sequence[float],
    parameters: dict[str, Any],
    lcm: Sequence[Sequence[str]],
    pum_diag: Sequence[bool],
) -> Tuple[List[bool], List[List[bool]], List[bool], bool]:
    cmv = _lic_cmv(numpoints, x, y, parameters)
    pum = _build_pum(cmv, lcm, pum_diag)
    fuv = _build_fuv(pum)
    launch = all(fuv)
    return cmv, pum, fuv, launch
